    36→#if BUILDFLAG(USE_ZYGOTE)
    37→ZygoteCommunication* RendererSandboxedProcessLauncherDelegate::GetZygote() {
    38→  const base::CommandLine& browser_command_line =
    39→      *base::CommandLine::ForCurrentProcess();
    40→  base::CommandLine::StringType renderer_prefix =
    41→      browser_command_line.GetSwitchValueNative(switches::kRendererCmdPrefix);
    42→  if (!renderer_prefix.empty())
    43→    return nullptr;
    44→  return GetGenericZygote();
    45→}
