    60→RendererSandboxedProcessLauncherDelegateWin::
    61→    RendererSandboxedProcessLauncherDelegateWin(
    62→        const base::CommandLine& cmd_line,
    63→        bool is_pdf_renderer,
    64→        bool is_jit_disabled)
    65→    : renderer_code_integrity_enabled_(
    66→          GetContentClient()->browser()->IsRendererCodeIntegrityEnabled()),
    67→      renderer_app_container_disabled_(
    68→          GetContentClient()->browser()->IsAppContainerDisabled(
    69→              sandbox::mojom::Sandbox::kRenderer)),
    70→      is_pdf_renderer_(is_pdf_renderer) {
    71→  // PDF renderers must be jitless.
    72→  CHECK(!is_pdf_renderer || is_jit_disabled);
    73→  if (is_jit_disabled) {
    74→    dynamic_code_can_be_disabled_ = true;
    75→    return;
    76→  }
    77→  if (cmd_line.HasSwitch(blink::switches::kJavaScriptFlags)) {
    78→    std::string js_flags =
    79→        cmd_line.GetSwitchValueASCII(blink::switches::kJavaScriptFlags);
    80→    std::vector<std::string_view> js_flag_list = base::SplitStringPiece(
    81→        js_flags, ",", base::TRIM_WHITESPACE, base::SPLIT_WANT_NONEMPTY);
    82→    for (const auto& js_flag : js_flag_list) {
    83→      if (js_flag == "--jitless") {
    84→        // If v8 is running jitless then there is no need for the ability to
    85→        // mark writable pages as executable to be available to the process.
    86→        dynamic_code_can_be_disabled_ = true;
    87→        break;
    88→      }
    89→    }
    90→  }
    91→}
    92→
    93→std::string RendererSandboxedProcessLauncherDelegateWin::GetSandboxTag() {
    94→  if (is_pdf_renderer_) {
    95→    // All pdf renderers are jitless so only need one tag for these.
    96→    return sandbox::policy::SandboxWin::GetSandboxTagForDelegate(
    97→        "renderer-pdfium", GetSandboxType());
    98→  } else {
    99→    // Some renderers can be jitless so need different tags.
   100→    return sandbox::policy::SandboxWin::GetSandboxTagForDelegate(
   101→        dynamic_code_can_be_disabled_ ? "renderer-jitless" : "renderer",
   102→        GetSandboxType());
   103→  }
   104→}
   105→
   106→bool RendererSandboxedProcessLauncherDelegateWin::InitializeConfig(
   107→    sandbox::TargetConfig* config) {
   108→  DCHECK(!config->IsConfigured());
   109→
   110→  sandbox::policy::SandboxWin::AddBaseHandleClosePolicy(config);
   111→
   112→  ContentBrowserClient::AppContainerFlags ac_flags(
   113→      ContentBrowserClient::AppContainerFlags::kAppContainerFlagNone);
   114→  if (renderer_app_container_disabled_) {
   115→    ac_flags = ContentBrowserClient::AppContainerFlags::
   116→        kAppContainerFlagDisableAppContainer;
   117→  }
   118→  const std::wstring& sid =
   119→      GetContentClient()->browser()->GetAppContainerSidForSandboxType(
   120→          GetSandboxType(), ac_flags);
   121→  if (!sid.empty()) {
   122→    sandbox::policy::SandboxWin::AddAppContainerPolicy(config, sid.c_str());
   123→  }
   124→
   125→  // If the renderer process is protected by code integrity, more
   126→  // mitigations become available.
   127→  if (renderer_code_integrity_enabled_ && dynamic_code_can_be_disabled_) {
   128→    sandbox::MitigationFlags mitigation_flags =
   129→        config->GetDelayedProcessMitigations();
   130→    mitigation_flags |= sandbox::MITIGATION_DYNAMIC_CODE_DISABLE;
   131→    if (sandbox::SBOX_ALL_OK !=
   132→        config->SetDelayedProcessMitigations(mitigation_flags)) {
   133→      return false;
   134→    }
   135→  }
   136→
   137→  config->SetFilterEnvironment(/*filter=*/true);
   138→
   139→  ContentBrowserClient::ChildSpawnFlags flags(
   140→      ContentBrowserClient::ChildSpawnFlags::kChildSpawnFlagNone);
   141→  if (renderer_code_integrity_enabled_) {
   142→    flags = ContentBrowserClient::ChildSpawnFlags::
   143→        kChildSpawnFlagRendererCodeIntegrity;
   144→  }
   145→  return GetContentClient()->browser()->PreSpawnChild(
   146→      config, sandbox::mojom::Sandbox::kRenderer, flags);
   147→}
   148→
   149→void RendererSandboxedProcessLauncherDelegateWin::PostSpawnTarget(
   150→    base::ProcessHandle process) {
   151→  FILETIME creation_time, exit_time, kernel_time, user_time;
   152→  // Should never fail. If it does, then something really bad has happened, such
   153→  // as something external unsuspending the renderer process.
   154→  if (!::GetProcessTimes(process, &creation_time, &exit_time, &kernel_time,
   155→                         &user_time)) {
   156→    return;
   157→  }
   158→
   159→  // These should always be zero but if they are not, then something on the
   160→  // client has triggered execution in the child process putting it into a
   161→  // undefined state. Try and detect this here to diagnose this happening in the
   162→  // wild.
   163→  base::UmaHistogramBoolean(
   164→      "BrowserRenderProcessHost.SuspendedChild.UserExecutionRecorded",
   165→      base::TimeDelta::FromFileTime(user_time).InMicroseconds() > 0);
   166→  base::UmaHistogramBoolean(
   167→      "BrowserRenderProcessHost.SuspendedChild.KernelExecutionRecorded",
   168→      base::TimeDelta::FromFileTime(kernel_time).InMicroseconds() > 0);
   169→}
   170→
   171→bool RendererSandboxedProcessLauncherDelegateWin::CetCompatible() {
   172→  // Disable CET for renderer because v8 deoptimization swaps stacks in a
   173→  // non-compliant way. CET can be enabled where the renderer is known to
   174→  // be jitless.
   175→  return dynamic_code_can_be_disabled_;
   176→}
   177→
   178→bool RendererSandboxedProcessLauncherDelegateWin::
   179→    ShouldUseUntrustedMojoInvitation() {
   180→  return true;
   181→}
